Q1 is an optimisation problem so we can use dynamic programming to search the array with max sum. Here is Java code

```
public class Q1 {

	private static int solution(List<Integer> arr, int p, int q, int r) {
		return dp(arr, p, q, r, new HashMap<>());
	}

	private static int dp(List<Integer> arr, int p, int q, int r, Map<String, Integer> memo) {
		int sum = arr.stream().mapToInt(i -> i).sum();
		if (p == 0 && q == 0 && r == 0) {
			return sum;
		}

		String key = p + "" + q + "" + r + "" + sum;
		if (memo.containsKey(key)) {
			return memo.get(key);
		}

		int res = Integer.MIN_VALUE;

		if (p > 0) {
			for (int i = 0; i < arr.size(); i++) {
				List<Integer> temp = new ArrayList<>(arr);
				temp.remove(i);
				res = Math.max(dp(temp, p - 1, q, r, memo), res);
			}
		}

		if (q > 0) {
			for (int i = 0; i < arr.size() - 1; i++) {
				List<Integer> temp = new ArrayList<>(arr);
				temp.remove(i);
				temp.remove(i);
				res = Math.max(dp(temp, p, q - 1, r, memo), res);
			}
		}

		if (r > 0) {
			for (int i = 0; i < arr.size() - 2; i++) {
				List<Integer> temp = new ArrayList<>(arr);
				temp.remove(i);
				temp.remove(i);
				temp.remove(i);
				res = Math.max(dp(temp, p, q, r - 1, memo), res);
			}
		}

		memo.put(key, res);
		return res;
	}

	public static void main(String[] args) {
		System.out.println(
				solution(Arrays.asList(3,1,0,5,1,6,5,-1,-100), 1, 1, 1));
	}
}
```

